"""
二维码安全管理模块
提供硬编码二维码和哈希验证功能，防止收款二维码被篡改
"""

import hashlib
import base64
import logging
from PySide6.QtGui import QPixmap
from PySide6.QtCore import QByteArray

logger = logging.getLogger(__name__)


class QRCodeSecurityManager:
    """二维码安全管理器"""

    # 硬编码的二维码图片 (Base64格式)
    # 使用方法：将你的二维码图片转换为Base64字符串后替换以下内容
    # 转换命令：python -c "import base64; print(base64.b64encode(open('wechat_qr.png', 'rb').read()).decode())"

    WECHAT_QR_BASE64 = """""".strip()

    # 预计算的SHA256哈希值（用于验证二维码完整性）
    # 计算命令：python -c "import hashlib, base64; data=base64.b64decode('your_base64'); print(hashlib.sha256(data).hexdigest())"


    ALIPAY_QR_BASE64 = """""".strip()
    WECHAT_QR_HASH = "19d89699ff8654b9e4245236ca77c9654cf140134eb1b1319a93ee0c238a38da"
    ALIPAY_QR_HASH = "7de5cfe83a9bf096ef21999f6622bf5cb04609f03e2ca4fc3748c2a2ba063e76"

    @classmethod
    def verify_integrity(cls, base64_data: str, expected_hash: str) -> bool:
        """
        验证Base64编码数据的完整性

        Args:
            base64_data: Base64编码的图片数据
            expected_hash: 预期的SHA256哈希值

        Returns:
            bool: 验证通过返回True，否则返回False
        """
        try:
            # 解码Base64数据
            decoded_data = base64.b64decode(base64_data)

            # 计算SHA256哈希
            actual_hash = hashlib.sha256(decoded_data).hexdigest()

            # 比对哈希值
            return actual_hash == expected_hash
        except Exception as e:
            logger.info(f"哈希验证失败: {e}")
            return False

    @classmethod
    def get_wechat_qrcode(cls) -> QPixmap:
        """
        获取微信收款二维码（经过完整性验证）

        Returns:
            QPixmap: 二维码图片对象，验证失败返回空QPixmap
        """
        # 验证完整性
        if not cls.verify_integrity(cls.WECHAT_QR_BASE64, cls.WECHAT_QR_HASH):
            logger.info("警告：微信二维码完整性验证失败！可能被篡改！")
            return QPixmap()

        try:
            # 解码Base64并加载为QPixmap
            qr_data = base64.b64decode(cls.WECHAT_QR_BASE64)
            qr_array = QByteArray(qr_data)
            pixmap = QPixmap()
            # 不指定格式，让Qt自动检测（支持PNG、JPEG等）
            pixmap.loadFromData(qr_array)
            return pixmap
        except Exception as e:
            logger.info(f"加载微信二维码失败: {e}")
            return QPixmap()

    @classmethod
    def get_alipay_qrcode(cls) -> QPixmap:
        """
        获取支付宝收款二维码（经过完整性验证）

        Returns:
            QPixmap: 二维码图片对象，验证失败返回空QPixmap
        """
        # 验证完整性
        if not cls.verify_integrity(cls.ALIPAY_QR_BASE64, cls.ALIPAY_QR_HASH):
            logger.info("警告：支付宝二维码完整性验证失败！可能被篡改！")
            return QPixmap()

        try:
            # 解码Base64并加载为QPixmap
            qr_data = base64.b64decode(cls.ALIPAY_QR_BASE64)
            qr_array = QByteArray(qr_data)
            pixmap = QPixmap()
            # 不指定格式，让Qt自动检测（支持PNG、JPEG等）
            pixmap.loadFromData(qr_array)
            return pixmap
        except Exception as e:
            logger.info(f"加载支付宝二维码失败: {e}")
            return QPixmap()

    @classmethod
    def update_qrcode(cls, qr_type: str, image_path: str):
        """
        辅助工具：更新二维码（用于开发时生成Base64和哈希值）

        Args:
            qr_type: 'wechat' 或 'alipay'
            image_path: 二维码图片路径

        使用示例：
            QRCodeSecurityManager.update_qrcode('wechat', 'wechat_qr.png')
        """
        try:
            with open(image_path, 'rb') as f:
                image_data = f.read()

            # 生成Base64
            base64_str = base64.b64encode(image_data).decode('utf-8')

            # 生成SHA256哈希
            hash_value = hashlib.sha256(image_data).hexdigest()

            logger.info(f"\n=== {qr_type.upper()} 二维码更新信息 ===")
            logger.info(f"\n将以下内容复制到 QRCodeSecurityManager 类中：\n")
            logger.info(f"{qr_type.upper()}_QR_BASE64 = '''")
            logger.info(base64_str)
            logger.info(f"'''.strip().replace('\\n', '')\n")
            logger.info(f"{qr_type.upper()}_QR_HASH = \"{hash_value}\"\n")
            logger.info("=" * 50)

        except Exception as e:
            logger.info(f"更新二维码失败: {e}")


def generate_qrcode_from_file(wechat_path: str = None, alipay_path: str = None):
    """
    辅助函数：从文件生成Base64和哈希值

    使用方法：
        python -c "from utils.qrcode_security import generate_qrcode_from_file; \
                   generate_qrcode_from_file('wechat_qr.png', 'alipay_qr.png')"
    """
    if wechat_path:
        logger.info("\n处理微信二维码...")
        QRCodeSecurityManager.update_qrcode('wechat', wechat_path)

    if alipay_path:
        logger.info("\n处理支付宝二维码...")
        QRCodeSecurityManager.update_qrcode('alipay', alipay_path)


if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO, format="%(message)s")
    import sys

    logger.info("""
╔══════════════════════════════════════════════════════════════════╗
║           二维码安全管理工具 - 生成Base64和哈希值               ║
╚══════════════════════════════════════════════════════════════════╝

使用方法：
  python utils/qrcode_security.py wechat_qr.png alipay_qr.png

说明：
  1. 将你的收款二维码图片放在项目根目录
  2. 运行此脚本生成Base64编码和SHA256哈希值
  3. 将生成的内容复制到 QRCodeSecurityManager 类中
  4. 删除原始图片文件（已硬编码到代码中）

安全特性：
  ✓ 二维码硬编码在代码中，无法被外部文件替换
  ✓ SHA256哈希验证，确保代码中的二维码未被篡改
  ✓ 双重保护机制，最大化安全性
    """)

    if len(sys.argv) > 1:
        wechat_path = sys.argv[1] if len(sys.argv) > 1 else None
        alipay_path = sys.argv[2] if len(sys.argv) > 2 else None
        generate_qrcode_from_file(wechat_path, alipay_path)
    else:
        logger.info("请提供二维码图片路径作为参数")
        logger.info("示例：python utils/qrcode_security.py wechat_qr.png alipay_qr.png")
